" f" Среднее: {sum(values)/len(values):.2f}" ) # ── Crypto: math helpers ────────────────────────────────────────────────────── def _ema(prices: list[float], period: int) -> list[float]: """Exponential moving average.""" k = 2.0 / (period + 1) result = [] prev = prices[0] for p in prices: prev = p * k + prev * (1 - k) result.append(prev) return result def _calc_rsi(closes: list[float], period: int = 14) -> float: """RSI(period) — classic Wilder smoothing.""" if len(closes) < period + 1: return 50.0 deltas = [closes[i] - closes[i - 1] for i in range(1, len(closes))] gains = [max(d, 0.0) for d in deltas] losses = [max(-d, 0.0) for d in deltas] avg_gain = sum(gains[:period]) / period avg_loss = sum(losses[:period]) / period for i in range(period, len(deltas)): avg_gain = (avg_gain * (period - 1) + gains[i]) / period avg_loss = (avg_loss * (period - 1) + losses[i]) / period if avg_loss == 0: return 100.0 rs = avg_gain / avg_loss return round(100 - 100 / (1 + rs), 2) def _calc_macd(closes: list[float], fast: int = 12, slow: int = 26, signal: int = 9): """Returns (macd_line, signal_line) — last values.""" if len(closes) < slow + signal: return 0.0, 0.0 ema_fast = _ema(closes, fast) ema_slow = _ema(closes, slow) macd_series = [f - s for f, s in zip(ema_fast, ema_slow)] signal_series = _ema(macd_series, signal) return round(macd_series[-1], 6), round(signal_series[-1], 6) def _derive_signal(rsi: float, macd: float, sig: float, price: float, ma20) -> str: """Simple rule-based signal.""" bullish = 0 bearish = 0 if rsi < 30: bullish += 2 elif rsi > 70: bearish += 2 if macd > sig: bullish += 1 else: bearish += 1 if ma20 and price > ma20: bullish += 1 elif ma20 and price < ma20: bearish += 1 if bullish > bearish: return "BUY 🟢" elif bearish > bullish: return "SELL 🔴" return "HOLD ⚪" # ── Crypto tools ────────────────────────────────────────────────────────────── @mcp.tool() def get_crypto_klines(symbol: str = "BTCUSDT", interval: str = "1h", limit: int = 50) -> str: """Fetch OHLCV candlestick data from Binance for crypto analysis. symbol examples: BTCUSDT, ETHUSDT, SOLUSDT, BNBUSDT. interval: 15m, 1h, 4h, 1d. limit: number of candles (max 500). Returns JSON array with ts/open/high/low/close/volume fields.""" url = ( f"https://api.binance.com/api/v3/klines" f"?symbol={symbol.upper()}&interval={interval}&limit={limit}" ) try: r = requests.get(url, timeout=10) data = r.json() if isinstance(data, dict) and data.get("code"): return f"Binance error: {data.get('msg', data)}" candles = [ { "ts": c[0], "open": float(c[1]), "high": float(c[2]), "low": float(c[3]), "close": float(c[4]), "volume": float(c[5]), } for c in data ] return json.dumps(candles) except Exception as e: return f"Error fetching klines: {e}" @mcp.tool() def calculate_indicators(klines_json: str) -> str: """Calculate technical indicators (RSI, MACD, MA) from klines data returned by get_crypto_klines. Input: JSON string from get_crypto_klines. Returns: RSI(14), MACD(12,26,9), MA20, MA50, price summary and trading signal (BUY/SELL/HOLD).""" try: candles = json.loads(klines_json) except Exception: return "Error: invalid JSON. Pass output of get_crypto_klines directly." if not candles or len(candles) < 2: return "Not enough data (need at least 2 candles)." closes = [c["close"] for c in candles] current = closes[-1] symbol_hint = f"Last price: {current:.4f}" ma20 = round(sum(closes[-20:]) / min(20, len(closes)), 4) ma50 = round(sum(closes[-50:]) / min(50, len(closes)), 4) if len(closes) >= 10 else None rsi = _calc_rsi(closes) macd_line, signal_line = _calc_macd(closes) histogram = round(macd_line - signal_line, 6) signal = _derive_signal(rsi, macd_line, signal_line, current, ma20) rsi_zone = "перепродан (<30)" if rsi < 30 else "перекуплен (>70)" if rsi > 70 else "нейтральная зона" lines = [ f"── Технический анализ ({len(closes)} свечей) ──", f"{symbol_hint}", f"MA(20): {ma20}", ] if ma50: lines.append(f"MA(50): {ma50}") lines += [ f"RSI(14): {rsi} [{rsi_zone}]",
